kernel void Fan1(global float *m, global float *a, int Size, int t)
{
    int idx = get_local_id(0) + get_group_id(0) * get_local_size(0);

    if(idx >= Size-1-t) return;

    m[Size*(idx+t+1)+t] = a[Size*(idx+t+1)+t] / a[Size*t+t];
}

kernel void Fan2(global float *m, global float *a, global float *b, int Size, int j1, int t)
{
    int xidx = get_local_id(0) + get_group_id(0) * get_local_size(0);
    int yidx = get_local_id(1) + get_group_id(1) * get_local_size(1);

    if(xidx >= Size-1-t) return;
    if(yidx >= Size-t) return;

    a[Size*(xidx+1+t)+(yidx+t)] -= m[Size*(xidx+1+t)+t] * a[Size*t+(yidx+t)];

    if(yidx == 0){
        b[xidx+1+t] -= m[Size*(xidx+1+t)+t] * b[t];
    }
}
